import{_ as t,o,c as s,a2 as a}from"./chunks/framework.CKCxdkvf.js";const g=JSON.parse('{"title":"Provenance + credits backlog","description":"","frontmatter":{},"headers":[],"relativePath":"wip/provenance-backlog.md","filePath":"wip/provenance-backlog.md"}'),i={name:"wip/provenance-backlog.md"};function n(r,e,c,d,l,h){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="provenance-credits-backlog" tabindex="-1">Provenance + credits backlog <a class="header-anchor" href="#provenance-credits-backlog" aria-label="Permalink to &quot;Provenance + credits backlog&quot;">​</a></h1><p>This file is the rolling backlog for <strong>provenance, attribution, and credits</strong> ideas that are not yet shipped. ADR-047 (&quot;Provenance manifests + license stewardship&quot;) locked the data model and pipeline; this list keeps the <strong>next-step ideas</strong> in one place so they don&#39;t get lost as scattered TODOs across the codebase.</p><blockquote><p>Add new ideas here rather than as inline <code>// TODO</code>s. When an item ships, move its bullet into the relevant ADR (047 or a successor) and delete it here.</p></blockquote><hr><h2 id="cadence" tabindex="-1">Cadence <a class="header-anchor" href="#cadence" aria-label="Permalink to &quot;Cadence&quot;">​</a></h2><ul><li>[ ] <strong>Per-locale staleness check.</strong> A linter that flags when <code>static/data/i18n/en-US/missions/&lt;id&gt;.json</code> has changed in the last N commits but the corresponding <code>es/</code>, <code>de/</code>, … overlay has not. Surface the result in <code>validate-data</code> so a translator can pick up the diff in the next sweep.</li><li>[ ] <strong>Periodic Wikimedia category sweep.</strong> A weekly job that hits Commons categories likely to contain new mission imagery (e.g. <code>Category:Photographs by Mars Express</code>, <code>Category:Chang&#39;e_5_mission</code>, <code>Category:JWST images</code>) and writes candidate filenames into a &quot;new since last sweep&quot; digest under <code>docs/provenance/sweeps/YYYY-MM-DD.md</code>. Maintainers can promote candidates into <code>WIKIMEDIA_*_GALLERY</code> lists by hand.</li><li>[ ] <strong>Weekly link-check GH Action.</strong> HEAD-checks every <code>source_url</code> in <code>image-provenance.json</code> and <code>text-sources.json</code>. Failures open or update a tracking issue automatically; the run report is committed under <code>docs/provenance/link-checks/YYYY-MM-DD.md</code>. Keeps &quot;the source URL still works&quot; honest as upstream pages move.</li><li>[ ] <strong>PR comment hook.</strong> On every PR that touches <code>static/images/**</code>, <code>static/textures/**</code>, <code>static/logos/**</code>, or any provenance manifest, post the <code>last-fetch-diff.md</code> digest as a PR comment so reviewers see the attribution delta without opening files.</li><li>[ ] <strong>Diff-report drift sentinel.</strong> Today the diff report is informational. Promote it to fail-closed: if a previously-shipped manifest entry loses its <code>license_short</code>, <code>author</code>, or <code>revid</code> between runs, the build fails until the entry is reviewed.</li></ul><h2 id="detection-regression" tabindex="-1">Detection / regression <a class="header-anchor" href="#detection-regression" aria-label="Permalink to &quot;Detection / regression&quot;">​</a></h2><ul><li>[ ] <strong>Sentry breadcrumb when a UI lightbox renders without provenance.</strong> Helps detect drift between the manifest and on-disk images at runtime in the wild — e.g. a CDN cache hands the user an image we removed from the manifest. Wire as a single <code>console.warn</code> + Sentry breadcrumb.</li><li>[ ] <strong>Playwright visual regression on <code>/credits</code>.</strong> Snapshots of the en-US <code>/credits</code> page and one non-English locale, sized for mobile + desktop. Fails when grouping or layout changes silently.</li><li>[ ] <strong>Type-level guarantee on i18n keys for credits.</strong> Today <code>credits_*</code> keys are just strings; a new section without an i18n key compiles silently. A lint rule (or a test that walks <code>pathToRouteKey</code> outputs and asserts each maps to an <code>m.credits_used_route_*</code> function) catches that drift.</li></ul><h2 id="authoring-ownership" tabindex="-1">Authoring + ownership <a class="header-anchor" href="#authoring-ownership" aria-label="Permalink to &quot;Authoring + ownership&quot;">​</a></h2><ul><li>[ ] <strong>CODEOWNERS entry.</strong> Require owner review on changes to <code>static/data/image-provenance.json</code>, <code>static/data/text-sources.json</code>, <code>static/data/source-logos.json</code>, <code>static/data/license-waivers.json</code>, and any file under <code>static/images/**</code>. Light-weight: prevents single-developer license waiver merges.</li><li>[ ] <strong>Authoring contract in PR template.</strong> Add a checkbox on the default PR template: &quot;If this PR adds a new image, planet/mission/site description, or external text fragment, did you update the matching manifest?&quot;</li><li>[ ] <strong><code>scripts/check-provenance-drift.ts</code>.</strong> A pre-push hook that runs <code>build-image-provenance --dry-run</code> and fails if <code>image-provenance.json</code> would change. Stops the case where someone hand-edits an image without re-running the manifest builder.</li></ul><h2 id="public-credits-surface" tabindex="-1">Public credits surface <a class="header-anchor" href="#public-credits-surface" aria-label="Permalink to &quot;Public credits surface&quot;">​</a></h2><ul><li>[ ] <strong>Search / filter on <code>/credits</code>.</strong> Filter by source, license, type (photo/text), category. Useful once the manifest grows past ~600 photos; defer until that&#39;s a problem.</li><li>[ ] <strong>Per-source <code>?source=nasa</code> deep links.</strong> Today the page uses anchor links. Adding query-param deep links makes individual source sections shareable.</li><li>[ ] <strong>Pagination / virtualization</strong> — the page is plain HTML lists today. Revisit when render time crosses ~250 ms on the smallest target device.</li><li>[ ] <strong>Per-image lightbox on <code>/credits</code> thumbs.</strong> Right now thumbs link out to the original Commons page; a lightbox-style modal could keep users in-app and still preserve the source link.</li><li>[ ] <strong>Author-level credit lines.</strong> Where <code>author</code> is a Wikimedia username, link it to the Commons user page instead of just rendering the username.</li></ul><h2 id="coverage-gaps" tabindex="-1">Coverage gaps <a class="header-anchor" href="#coverage-gaps" aria-label="Permalink to &quot;Coverage gaps&quot;">​</a></h2><ul><li>[ ] <strong>Backfill per-mission text-sources entries.</strong> The current <code>text-sources.json</code> ships with category-baseline entries plus the highest-profile per-mission rows (Apollo 11, Curiosity, Mars Express, Hope, Chandrayaan-3). Extend coverage to all 36 missions, ~9 planets, ~24 moon sites, ~17 earth objects, and ISS modules so each entity has its primary-source attribution row.</li><li>[ ] <strong>Reviewer ids on translations.</strong> <code>translation_status</code> exists in the schema but most translations don&#39;t yet record a <code>translation_reviewer</code>. Define the convention (GitHub handle? human name?) and backfill.</li><li>[ ] <strong>Locale-specific source notes.</strong> Localised overlays may paraphrase from a locale&#39;s primary press kit (e.g. ISRO Hindi-language press kit for Chandrayaan). Add an <code>overlay_locale</code> field on <code>text-sources.json</code> entries to record that.</li></ul><h2 id="out-of-scope-intentional" tabindex="-1">Out of scope (intentional) <a class="header-anchor" href="#out-of-scope-intentional" aria-label="Permalink to &quot;Out of scope (intentional)&quot;">​</a></h2><ul><li><strong>Runtime imagery hops.</strong> ADR-016 still rules; live agency calls at view time are not on the table.</li><li><strong>Per-photo CC-BY chain of custody on social shares.</strong> When <code>/credits</code> is link-shared, the page itself credits the source. We do not stamp share thumbnails individually.</li></ul><hr><p><em>Updated when ideas land or new ideas surface. Cite this file from PRs that defer provenance work.</em></p>',18)])])}const p=t(i,[["render",n]]);export{g as __pageData,p as default};
